import React from 'react';
import ProductCard from '../product/productcart';

const ProductGrid = ({ title, products, subtitle }) => {
  if (!products || products.length === 0) return null;

  return (
    <section className="py-6 md:py-10 bg-gray-50">
      <div className="container mx-auto px-4">
        <div className="flex items-end justify-between mb-4 md:mb-6">
          <div>
            <h2 className="text-xl md:text-2xl font-bold text-gray-900">
              {title}
            </h2>
            {subtitle && (
              <p className="text-sm text-gray-500 mt-1">{subtitle}</p>
            )}
          </div>
          <button className="text-sm font-medium text-primary-700 hover:text-primary-800 hidden md:block">
            View All
          </button>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-3 md:gap-4">
          {products.map((product) => (
            <ProductCard key={product._id} product={product} />
          ))}
        </div>

        <button className="w-full mt-4 py-2.5 bg-white border border-gray-200 rounded-lg text-sm font-medium text-gray-700 md:hidden hover:bg-gray-50">
          View All Products
        </button>
      </div>
    </section>
  );
};

export default ProductGrid;
